4: define('forum/topic/postTools', [
5: 	'share',
6: 	'navigator',
7: 	'components',
8: 	'translator',
9: 	'forum/topic/votes',
10: 	'api',
11: 	'bootbox',
12: 	'alerts',
13: 	'hooks',
14: 	'helpers',
15: ], function (share, navigator, components, translator, votes, api, bootbox, alerts, hooks, helpers) {
16: 	const PostTools = {};
17: 
18: 	let staleReplyAnyway = false;
19: 
20: 	PostTools.init = function (tid) {
21: 		staleReplyAnyway = false;
22: 
23: 		renderMenu();
24: 
25: 		addPostHandlers(tid);
26: 
27: 		share.addShareHandlers(ajaxify.data.titleRaw);
28: 
29: 		votes.addVoteHandler();
30: 
31: 		PostTools.updatePostCount(ajaxify.data.postcount);
32: 	};
33: 
34: 	function renderMenu() {
35: 		const container = document.querySelector('[component="topic"]');
36: 		if (!container) {
37: 			return;
38: 		}
39: 		$('[component="topic"]').on('show.bs.dropdown', '[component="post/tools"]', function () {
40: 			const $this = $(this);
41: 			const dropdownMenu = $this.find('.dropdown-menu');
42: 			const { top } = this.getBoundingClientRect();
43: 			$this.toggleClass('dropup', top > window.innerHeight / 2);
44: 
45: 			if (dropdownMenu.attr('data-loaded')) {
46: 				return;
47: 			}
48: 			dropdownMenu.html(helpers.generatePlaceholderWave([
49: 				3, 5, 9, 7, 10, 'divider', 10,
50: 			]));
51: 
52: 			const postEl = $this.parents('[data-pid]');
53: 			const pid = postEl.attr('data-pid');
54: 			const index = parseInt(postEl.attr('data-index'), 10);
55: 
56: 			socket.emit('posts.loadPostTools', { pid: pid }, async (err, data) => {
57: 				if (err) {
58: 					return alerts.error(err);
59: 				}
60: 				data.posts.display_move_tools = data.posts.display_move_tools && index !== 0;
61: 
62: 				const html = await app.parseAndTranslate('partials/topic/post-menu-list', data);
63: 				const clipboard = require('clipboard');
64: 
65: 				dropdownMenu.attr('data-loaded', 'true').html(html);
66: 
67: 				new clipboard('[data-clipboard-text]');
68: 
69: 				hooks.fire('action:post.tools.load', {
70: 					element: dropdownMenu,
71: 				});
72: 			});
73: 		});
74: 	}
75: 
