529: 	async function delayedTooltip() {
530: 		let selectionTooltip = $('[component="selection/tooltip"]');
531: 		selectionTooltip.addClass('hidden');
532: 		if (selectionTooltip.attr('data-ajaxify') === '1') {
533: 			selectionTooltip.remove();
534: 			return;
535: 		}
536: 
537: 		const selection = window.getSelection();
538: 		if (selection.focusNode && selection.type === 'Range' && ajaxify.data.template.topic) {
539: 			const focusNode = $(selection.focusNode);
540: 			const anchorNode = $(selection.anchorNode);
541: 			const firstPid = anchorNode.parents('[data-pid]').attr('data-pid');
542: 			const lastPid = focusNode.parents('[data-pid]').attr('data-pid');
543: 			if (firstPid !== lastPid || !focusNode.parents('[component="post/content"]').length || !anchorNode.parents('[component="post/content"]').length) {
544: 				return;
545: 			}
546: 			const postEl = focusNode.parents('[data-pid]');
547: 			const selectionRange = selection.getRangeAt(0);
548: 			if (!postEl.length || selectionRange.collapsed) {
549: 				return;
550: 			}
551: 			const rects = selectionRange.getClientRects();
552: 			const lastRect = rects[rects.length - 1];
553: 
554: 			if (!selectionTooltip.length) {
555: 				selectionTooltip = await app.parseAndTranslate('partials/topic/selection-tooltip', ajaxify.data);
556: 				$('[component="selection/tooltip"]').remove();
557: 				selectionTooltip.addClass('hidden').appendTo('body');
558: 			}
559: 			selectionTooltip.off('click').on('click', '[component="selection/tooltip/quote"]', function () {
560: 				selectionTooltip.addClass('hidden');
561: 				onQuoteClicked(postEl.find('[component="post/quote"]'), ajaxify.data.tid);
562: 			});
563: 			selectionTooltip.removeClass('hidden');
564: 			$(window).one('action:ajaxify.start', function () {
565: 				selectionTooltip.attr('data-ajaxify', 1).addClass('hidden');
566: 				$(document).off('selectionchange', selectionChangeFn);
567: 			});
568: 			const tooltipWidth = selectionTooltip.outerWidth(true);
569: 			selectionTooltip.css({
570: 				top: lastRect.bottom + $(window).scrollTop(),
571: 				left: tooltipWidth > lastRect.width ? lastRect.left : lastRect.left + lastRect.width - tooltipWidth,
572: 			});
573: 		}
574: 	}
